from __future__ import annotations
from dataclasses import dataclass
from typing import Union, Optional, Tuple, Any


@dataclass
class ASTNode:
    type: str
    value: Optional[float] = None
    op: Optional[str] = None
    left: Optional[ASTNode] = None
    right: Optional[ASTNode] = None
    operand: Optional[ASTNode] = None


class Tokenizer:
    def __init__(self, expression: str):
        self.expression = expression
        self.pos = 0
        self.current_char = self.expression[self.pos] if self.expression else None

    def advance(self):
        self.pos += 1
        if self.pos >= len(self.expression):
            self.current_char = None
        else:
            self.current_char = self.expression[self.pos]

    def skip_whitespace(self):
        while self.current_char is not None and self.current_char.isspace():
            self.advance()

    def number(self) -> float:
        result = ""
        while self.current_char is not None and (
            self.current_char.isdigit() or self.current_char == "."
        ):
            result += self.current_char
            self.advance()
        return float(result)

    def get_next_token(self) -> Tuple[str, Any]:
        if self.current_char is None:
            return ("EOF", None)

        if self.current_char.isspace():
            self.skip_whitespace()
            return self.get_next_token()

        if self.current_char.isdigit() or self.current_char == ".":
            return ("NUMBER", self.number())

        if self.current_char == "+":
            self.advance()
            return ("PLUS", "+")

        if self.current_char == "-":
            self.advance()
            return ("MINUS", "-")

        if self.current_char == "*":
            self.advance()
            return ("MUL", "*")

        if self.current_char == "/":
            self.advance()
            return ("DIV", "/")

        if self.current_char == "(":
            self.advance()
            return ("LPAREN", "(")

        if self.current_char == ")":
            self.advance()
            return ("RPAREN", ")")

        raise ValueError(f"Invalid token: {self.current_char}")


class Parser:
    def __init__(self, tokenizer: Tokenizer):
        self.tokenizer = tokenizer
        self.current_token = self.tokenizer.get_next_token()

    def eat(self, token_type: str):
        if self.current_token[0] == token_type:
            self.current_token = self.tokenizer.get_next_token()
        else:
            raise ValueError(f"Expected {token_type}, got {self.current_token[0]}")

    def factor(self) -> ASTNode:
        token = self.current_token

        if token[0] == "NUMBER":
            self.eat("NUMBER")
            return ASTNode(type="number", value=float(token[1]))

        if token[0] == "LPAREN":
            self.eat("LPAREN")
            node = self.expr()
            self.eat("RPAREN")
            return node

        if token[0] == "MINUS":
            self.eat("MINUS")
            node = ASTNode(type="unary", op="-", operand=self.factor())
            return node

        if token[0] == "PLUS":
            self.eat("PLUS")
            return self.factor()

        raise ValueError(f"Unexpected token: {token[0]}")

    def term(self) -> ASTNode:
        node = self.factor()

        while self.current_token[0] in ("MUL", "DIV"):
            token = self.current_token
            if token[0] == "MUL":
                self.eat("MUL")
            elif token[0] == "DIV":
                self.eat("DIV")

            node = ASTNode(
                type="binop", op=str(token[1]), left=node, right=self.factor()
            )

        return node

    def expr(self) -> ASTNode:
        node = self.term()

        while self.current_token[0] in ("PLUS", "MINUS"):
            token = self.current_token
            if token[0] == "PLUS":
                self.eat("PLUS")
            elif token[0] == "MINUS":
                self.eat("MINUS")

            node = ASTNode(type="binop", op=str(token[1]), left=node, right=self.term())

        return node

    def parse(self) -> ASTNode:
        if self.current_token[0] == "EOF":
            raise ValueError("Empty expression")

        node = self.expr()

        if self.current_token[0] != "EOF":
            raise ValueError(
                f"Unexpected token after expression: {self.current_token[0]}"
            )

        return node


def parse(expression: str) -> ASTNode:
    if not expression or not expression.strip():
        raise ValueError("Empty expression")

    tokenizer = Tokenizer(expression)
    parser = Parser(tokenizer)
    return parser.parse()


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        if node.value is None:
            raise ValueError("Number node has no value")
        return node.value

    if node.type == "unary":
        if node.operand is None:
            raise ValueError("Unary node has no operand")
        if node.op == "-":
            return -evaluate(node.operand)
        raise ValueError(f"Unknown unary operator: {node.op}")

    if node.type == "binop":
        if node.left is None or node.right is None:
            raise ValueError("Binary operation node missing operands")
        left = evaluate(node.left)
        right = evaluate(node.right)

        if node.op == "+":
            return left + right
        elif node.op == "-":
            return left - right
        elif node.op == "*":
            return left * right
        elif node.op == "/":
            if right == 0:
                raise ZeroDivisionError("Division by zero")
            return left / right
        else:
            raise ValueError(f"Unknown operator: {node.op}")

    raise ValueError(f"Unknown node type: {node.type}")
